for business in credit_card_businesses:
    description = business.get('description', '')
    business_id = business.get('business_id', '')

    # Look for categories after "services in" or similar phrases
    if 'services in' in description:
        # Extract the part after "services in" and before the period
        start = description.find('services in') + len('services in')
        end = description.find('.', start)
        if end == -1:
            end = len(description)

        category_part = description[start:end].strip()
        # Split by comma
        parts = category_part.split(',')
        categories = []
        for part in parts:
            # Clean up each category
            cleaned = part.replace('and', '').strip()
            if cleaned:
                categories.append(cleaned)
    else:
        # Fallback for other patterns
        categories = []

    if categories:
        business_categories[business_id] = categories
        for category in categories:
            category_counts[category] = category_counts.get(category, 0) + 1
    else:
        business_categories[business_id] = ['Unknown']
        category_counts['Unknown'] = category_counts.get('Unknown', 0) + 1

# Show results
print("\n=== Business Categories ===")
for biz_id, cats in business_categories.items():
    print(f"{biz_id}: {cats}")

print("\n=== Category Counts (sorted) ===")
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)
for cat, count in sorted_categories:
    print(f"{cat}: {count}")

# Get top category
if sorted_categories:
    top_category = sorted_categories[0]
    print(f"\n=== Top Category ===")
    print(f"{top_category[0]}: {top_category[1]} businesses")
else:
    print("\n=== No categories found ===")

result = {
    "category_counts": category_counts,
    "top_category": sorted_categories[0] if sorted_categories else None
}

